import { useState, useMemo, useEffect } from "react";

// Data encoded as base64 to avoid any parsing issues
const _B64 = "";

function decodeData() {
  const binary = atob(_B64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
  const json = new TextDecoder().decode(bytes);
  return JSON.parse(json);
}

const _DB = decodeData();
const LOCO_LIST = _DB.l;
// Expand compressed keys back
const LOCOS = {};
Object.entries(_DB.d).forEach(([loco, rows]) => {
  LOCOS[loco] = rows.map(r => {
    if (r.n) return { type: "note", text: r.n };
    return {
      type: "record",
      pa_date: r.pd||"", location: r.lo||"", fault: r.fa||"",
      investigation: r.iv||"", comp_in: r.ci||"", comp_out: r.co||"",
      epd_date: r.ed||"", epd_reason: r.er||"", epd_in: r.ei||"",
      epd_out: r.eo||"", epd_type: r.et||"", remarks: r.rm||"",
    };
  });
});

const ALL_FLAT = [];
Object.entries(LOCOS).forEach(([loco_no, rows]) => {
  rows.forEach(r => { if (r.type === "record") ALL_FLAT.push({...r, loco_no}); });
});

const S = {
  bg:"#0d0d0d", surface:"#111", border:"#1e1e1e", accent:"#f5a623",
  accent2:"#2a1a00", text:"#e8e0cc", muted:"#555",
  green:"#1a3a00", greenB:"#4a8", greenT:"#7fc",
  red:"#3a0000", redB:"#f44", redT:"#f88",
};

const inp = {
  width:"100%", background:"#1a1a1a", border:"1px solid #2a2a2a",
  borderRadius:6, padding:"8px 10px", color:"#e8e0cc",
  fontFamily:"monospace", fontSize:13, boxSizing:"border-box",
};

function Badge({t}) {
  if (!t) return null;
  const mod = t.includes("Modified");
  return <span style={{
    background:mod?"#1a2a00":"#1a1200", border:"1px solid "+(mod?"#4a8":"#a84"),
    borderRadius:3, padding:"2px 6px", color:mod?"#7fc":"#fca",
    fontSize:10, fontFamily:"monospace", whiteSpace:"nowrap",
  }}>{t}</span>;
}

function Field({label, val}) {
  if (!val) return null;
  return (
    <div style={{display:"grid", gridTemplateColumns:"140px 1fr", gap:8,
      marginBottom:8, paddingBottom:8, borderBottom:"1px solid #1a1a1a"}}>
      <div style={{fontSize:10, color:"#888", letterSpacing:1}}>{label.toUpperCase()}</div>
      <div style={{fontSize:12, color:"#e8e0cc", lineHeight:1.5, wordBreak:"break-word"}}>{val}</div>
    </div>
  );
}

const EMPTY = {
  pa_date:"", location:"", fault:"", investigation:"",
  comp_in:"", comp_out:"", epd_date:"", epd_reason:"",
  epd_in:"", epd_out:"", epd_type:"Modified Kit", remarks:"",
};

export default function App() {
  const [tab, setTab] = useState("loco");
  const [selLoco, setSelLoco] = useState(null);
  const [selRec, setSelRec] = useState(null);
  const [q, setQ] = useState("");
  const [sf, setSf] = useState("");
  const [sc, setSc] = useState("");
  const [sd, setSd] = useState("");
  const [sl, setSl] = useState("");
  const [sbOpen, setSbOpen] = useState(true);
  const [showAdd, setShowAdd] = useState(false);
  const [form, setForm] = useState(EMPTY);
  const [custom, setCustom] = useState({});
  const [toast, setToast] = useState(null);

  useEffect(() => {
    try {
      const s = localStorage.getItem("loco_v4");
      if (s) setCustom(JSON.parse(s));
    } catch(e) {}
  }, []);

  const persist = (data) => {
    try { localStorage.setItem("loco_v4", JSON.stringify(data)); } catch(e) {}
  };

  const showT = (msg, type="ok") => {
    setToast({msg, type});
    setTimeout(() => setToast(null), 2500);
  };

  const allLocos = useMemo(() => {
    const s = new Set(LOCO_LIST);
    Object.keys(custom).forEach(l => s.add(l));
    return [...s].sort();
  }, [custom]);

  const locoRecs = useMemo(() => {
    if (!selLoco) return [];
    const base = (LOCOS[selLoco]||[]).filter(r => r.type === "record");
    const cust = (custom[selLoco]||[]).map(r => ({...r, _c:true}));
    return [...base, ...cust];
  }, [selLoco, custom]);

  const filtLocos = useMemo(() => {
    const qq = q.trim();
    return qq ? allLocos.filter(l => l.includes(qq)) : allLocos;
  }, [allLocos, q]);

  const searchRes = useMemo(() => {
    if (!sf && !sc && !sd && !sl) return [];
    let recs = [...ALL_FLAT];
    Object.entries(custom).forEach(([ln, rows]) => {
      rows.forEach(r => recs.push({...r, loco_no:ln, _c:true}));
    });
    return recs.filter(r => {
      const fM = !sf || (r.fault+r.investigation+r.epd_reason).toLowerCase().includes(sf.toLowerCase());
      const cM = !sc || (r.comp_in+r.comp_out+r.epd_in+r.epd_out).toLowerCase().includes(sc.toLowerCase());
      const dM = !sd || (r.pa_date+r.epd_date).toLowerCase().includes(sd.toLowerCase());
      const lM = !sl || r.loco_no.includes(sl.trim());
      return fM && cM && dM && lM;
    });
  }, [sf, sc, sd, sl, custom]);

  const totalRecs = ALL_FLAT.length + Object.values(custom).reduce((s,v)=>s+v.length,0);

  const addRecord = () => {
    if (!selLoco) { showT("Loco select karo!", "err"); return; }
    if (!form.fault && !form.epd_reason) { showT("Fault ya EPD Reason daalo!", "err"); return; }
    const upd = {...custom, [selLoco]: [...(custom[selLoco]||[]), {...form, type:"record"}]};
    setCustom(upd); persist(upd);
    setForm(EMPTY); setShowAdd(false);
    showT("Record add ho gaya ✓");
  };

  const addLoco = () => {
    const n = window.prompt("Naya loco number:");
    if (!n) return;
    const nn = n.trim();
    if (allLocos.includes(nn)) { showT(nn+" pehle se hai!", "err"); return; }
    const upd = {...custom, [nn]:[]};
    setCustom(upd); persist(upd);
    showT("Loco "+nn+" add ho gaya ✓");
  };

  const delRec = (loco, idx) => {
    const arr = [...(custom[loco]||[])];
    arr.splice(idx, 1);
    const upd = {...custom, [loco]:arr};
    setCustom(upd); persist(upd);
    showT("Record delete ho gaya", "warn");
  };

  const delLoco = () => {
    if (!window.confirm("Loco "+selLoco+" delete karo?")) return;
    const u = {...custom}; delete u[selLoco];
    setCustom(u); persist(u); setSelLoco(null);
    showT("Loco delete ho gaya", "warn");
  };

  const setF = (k,v) => setForm(p => ({...p, [k]:v}));

  const TC = {ok:"#003a00", err:"#5a0000", warn:"#3a2200"};
  const TB = {ok:"#4a8", err:"#f44", warn:"#f5a623"};

  return (
    <div style={{minHeight:"100vh", background:S.bg, fontFamily:"Courier New,monospace",
      color:S.text, display:"flex", flexDirection:"column"}}>

      {toast && (
        <div style={{position:"fixed", top:14, right:14, zIndex:9999,
          background:TC[toast.type], border:"1px solid "+TB[toast.type],
          borderRadius:8, padding:"10px 16px", color:"#fff", fontSize:13, fontWeight:"bold"}}>
          {toast.msg}
        </div>
      )}

      {/* HEADER */}
      <div style={{background:"linear-gradient(135deg,#1a1200,#0d0d0d)",
        borderBottom:"2px solid #f5a623", padding:"10px 16px",
        display:"flex", alignItems:"center", gap:10, flexShrink:0}}>
        <span style={{fontSize:20}}>🚂</span>
        <div style={{flex:1}}>
          <div style={{fontSize:13, fontWeight:"bold", color:"#f5a623", letterSpacing:2}}>LOCO FAULT TRACKER</div>
          <div style={{fontSize:9, color:S.muted, letterSpacing:1}}>{allLocos.length} LOCOS · {totalRecs} RECORDS</div>
        </div>
        <div style={{display:"flex", gap:6}}>
          {[["loco","🚂 LOCO"],["search","🔍 SEARCH"]].map(([id,lb]) => (
            <button key={id} onClick={()=>setTab(id)} style={{
              border:"1px solid #f5a623", borderRadius:20, padding:"5px 10px",
              fontSize:9, fontWeight:"bold", letterSpacing:1, cursor:"pointer",
              background:tab===id?"#f5a623":"transparent", color:tab===id?"#000":"#f5a623",
            }}>{lb}</button>
          ))}
        </div>
      </div>

      <div style={{display:"flex", flex:1, overflow:"hidden", height:"calc(100vh - 52px)"}}>

        {tab==="loco" && <>
          {/* SIDEBAR */}
          <div style={{
            width:sbOpen?170:36, background:S.surface, borderRight:"1px solid "+S.border,
            display:"flex", flexDirection:"column", flexShrink:0,
            transition:"width 0.2s", overflow:"hidden",
          }}>
            <div style={{display:"flex", alignItems:"center", padding:"7px",
              borderBottom:"1px solid "+S.border,
              justifyContent:sbOpen?"space-between":"center"}}>
              {sbOpen && <span style={{fontSize:9, color:"#f5a623", fontWeight:"bold", letterSpacing:1}}>
                LOCOS ({allLocos.length})
              </span>}
              <button onClick={()=>setSbOpen(!sbOpen)} style={{
                background:"transparent", border:"1px solid #2a2a2a",
                color:"#f5a623", borderRadius:3, padding:"2px 7px", fontSize:12, cursor:"pointer",
              }}>{sbOpen?"◀":"▶"}</button>
            </div>

            {sbOpen && <>
              <div style={{padding:"6px 6px 2px"}}>
                <input value={q} onChange={e=>setQ(e.target.value)}
                  placeholder="Search..." style={{...inp, fontSize:11, padding:"5px 8px"}}/>
              </div>
              <div style={{padding:"3px 6px 5px"}}>
                <button onClick={addLoco} style={{
                  width:"100%", background:S.green, border:"1px solid "+S.greenB,
                  color:S.greenT, borderRadius:6, padding:"4px 0",
                  fontSize:10, fontWeight:"bold", cursor:"pointer",
                }}>+ ADD LOCO</button>
              </div>
              <div style={{overflowY:"auto", flex:1}}>
                {filtLocos.map(l => {
                  const isC = !LOCO_LIST.includes(l);
                  const rc = (LOCOS[l]||[]).filter(r=>r.type==="record").length+(custom[l]||[]).length;
                  return (
                    <div key={l} onClick={()=>{setSelLoco(l);setShowAdd(false);}}
                      style={{padding:"6px 10px", cursor:"pointer",
                        background:selLoco===l?S.accent2:"transparent",
                        borderLeft:"3px solid "+(selLoco===l?"#f5a623":"transparent"),
                        display:"flex", justifyContent:"space-between", alignItems:"center"}}>
                      <span style={{fontSize:11, fontWeight:"bold",
                        color:selLoco===l?"#f5a623":S.text}}>
                        {isC?"★ ":""}{l}
                      </span>
                      <span style={{fontSize:9, color:S.muted}}>{rc}</span>
                    </div>
                  );
                })}
              </div>
            </>}

            {!sbOpen && selLoco && (
              <div style={{writingMode:"vertical-rl", color:"#f5a623",
                fontSize:11, fontWeight:"bold", textAlign:"center", padding:"10px 0"}}>
                {selLoco}
              </div>
            )}
          </div>

          {/* MAIN PANEL */}
          <div style={{flex:1, overflowY:"auto", padding:14}}>
            {!selLoco ? (
              <div style={{textAlign:"center", color:S.muted, marginTop:60, fontSize:14}}>
                ← Loco select karo
              </div>
            ) : <>
              <div style={{display:"flex", alignItems:"center", gap:8, marginBottom:12, flexWrap:"wrap"}}>
                <span style={{fontSize:16, color:"#f5a623", fontWeight:"bold"}}>🚂 {selLoco}</span>
                <span style={{fontSize:10, color:S.muted}}>{locoRecs.length} records</span>
                <div style={{marginLeft:"auto", display:"flex", gap:6}}>
                  <button onClick={()=>setShowAdd(!showAdd)} style={{
                    background:showAdd?S.green:"transparent", border:"1px solid "+S.greenB,
                    color:S.greenT, borderRadius:6, padding:"5px 10px",
                    fontSize:10, fontWeight:"bold", cursor:"pointer",
                  }}>➕ NEW RECORD</button>
                  {!LOCO_LIST.includes(selLoco) && (
                    <button onClick={delLoco} style={{
                      background:S.red, border:"1px solid "+S.redB, color:S.redT,
                      borderRadius:6, padding:"5px 10px", fontSize:10, fontWeight:"bold", cursor:"pointer",
                    }}>DELETE</button>
                  )}
                </div>
              </div>

              {showAdd && (
                <div style={{background:"#0d1a00", border:"1px solid "+S.greenB,
                  borderRadius:8, padding:14, marginBottom:14}}>
                  <div style={{fontSize:10, color:S.greenT, marginBottom:10, letterSpacing:1}}>
                    NAYA RECORD — {selLoco}
                  </div>
                  <div style={{display:"grid", gridTemplateColumns:"1fr 1fr", gap:8, marginBottom:8}}>
                    {[
                      ["pa_date","PA Date","DD.MM.YYYY"],
                      ["location","Location","No 08, Blade"],
                      ["fault","Fault/Reason","water leakage..."],
                      ["epd_date","EPD Date","DD.MM.YYYY"],
                      ["epd_reason","EPD Reason","Special Drive"],
                      ["epd_in","EPD In (Old)","1017-422"],
                      ["epd_out","EPD Out (New)","2020F473"],
                      ["comp_in","Component In","MAHLE, LINER..."],
                    ].map(([k,label,ph]) => (
                      <div key={k}>
                        <div style={{fontSize:9, color:"#888", letterSpacing:1, marginBottom:3}}>
                          {label.toUpperCase()}
                        </div>
                        <input value={form[k]} onChange={e=>setF(k,e.target.value)}
                          placeholder={ph} style={inp}/>
                      </div>
                    ))}
                  </div>
                  {[["investigation","Investigation"],["remarks","Remarks"]].map(([k,label]) => (
                    <div key={k} style={{marginBottom:8}}>
                      <div style={{fontSize:9, color:"#888", letterSpacing:1, marginBottom:3}}>
                        {label.toUpperCase()}
                      </div>
                      <textarea value={form[k]} onChange={e=>setF(k,e.target.value)}
                        rows={2} style={{...inp, resize:"vertical"}}/>
                    </div>
                  ))}
                  <div style={{marginBottom:10}}>
                    <div style={{fontSize:9, color:"#888", letterSpacing:1, marginBottom:3}}>EPD TYPE</div>
                    <select value={form.epd_type} onChange={e=>setF("epd_type",e.target.value)}
                      style={{...inp, width:"auto", minWidth:180}}>
                      {["Modified Kit","Modified EPD","Unmodified","Unmodified Kit"].map(o=>(
                        <option key={o}>{o}</option>
                      ))}
                    </select>
                  </div>
                  <div style={{display:"flex", gap:8}}>
                    <button onClick={addRecord} style={{
                      background:"#1a4000", border:"1px solid #5c5", color:"#8f8",
                      borderRadius:6, padding:"9px 20px", fontWeight:"bold", fontSize:13, cursor:"pointer",
                    }}>✓ SAVE</button>
                    <button onClick={()=>{setShowAdd(false);setForm(EMPTY);}} style={{
                      background:"transparent", border:"1px solid #333", color:"#888",
                      borderRadius:6, padding:"9px 14px", fontSize:12, cursor:"pointer",
                    }}>Cancel</button>
                  </div>
                </div>
              )}

              {(LOCOS[selLoco]||[]).filter(r=>r.type==="note").map((n,i) => (
                <div key={i} style={{background:"#1a1000", border:"1px solid #443",
                  borderRadius:6, padding:"8px 12px", marginBottom:8,
                  fontSize:11, color:"#fa8"}}>
                  📌 {n.text}
                </div>
              ))}

              {locoRecs.length === 0 ? (
                <div style={{color:S.muted, textAlign:"center", marginTop:40, fontSize:13}}>
                  Koi record nahi. NEW RECORD se add karo.
                </div>
              ) : (
                <div style={{border:"1px solid "+S.border, borderRadius:8, overflow:"hidden"}}>
                  <div style={{display:"grid", gridTemplateColumns:"95px 115px 1fr 95px 28px",
                    background:"#1e1600", padding:"7px 10px", fontSize:9,
                    color:"#f5a623", letterSpacing:1, borderBottom:"1px solid "+S.border}}>
                    <div>PA DATE</div><div>LOCATION</div>
                    <div>FAULT</div><div>EPD TYPE</div><div></div>
                  </div>
                  {locoRecs.map((r, i) => {
                    let ci = -1;
                    if (r._c) { let x=0; for(let j=0;j<i;j++){if(locoRecs[j]._c)x++;} ci=x; }
                    return (
                      <div key={i} onClick={()=>setSelRec({...r, _ln:selLoco})}
                        style={{display:"grid", gridTemplateColumns:"95px 115px 1fr 95px 28px",
                          padding:"8px 10px", borderBottom:"1px solid "+S.border,
                          background:r._c?"#0d1a00":i%2===0?S.surface:"#0f0f0f",
                          cursor:"pointer"}}>
                        <div style={{fontSize:11, color:S.muted, overflow:"hidden",
                          textOverflow:"ellipsis", whiteSpace:"nowrap"}}>{r.pa_date||"—"}</div>
                        <div style={{fontSize:11, overflow:"hidden",
                          textOverflow:"ellipsis", whiteSpace:"nowrap"}}>{r.location||"—"}</div>
                        <div style={{fontSize:11, overflow:"hidden",
                          textOverflow:"ellipsis", whiteSpace:"nowrap"}}>
                          {r._c&&<span style={{color:S.greenT,marginRight:4}}>★</span>}
                          {r.fault||r.epd_reason||"—"}
                        </div>
                        <div><Badge t={r.epd_type}/></div>
                        <div style={{textAlign:"center"}}>
                          {r._c && (
                            <span onClick={e=>{e.stopPropagation();delRec(selLoco,ci);}}
                              style={{color:S.redB, cursor:"pointer", fontSize:14}}>✕</span>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </>}
          </div>
        </>}

        {tab==="search" && (
          <div style={{flex:1, padding:14, overflowY:"auto"}}>
            <div style={{display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:12}}>
              {[
                {label:"🚂 LOCO NO.", val:sl, set:setSl, ph:"e.g. 40004"},
                {label:"⚠️ FAULT/REASON", val:sf, set:setSf, ph:"water leakage..."},
                {label:"🔩 COMPONENT", val:sc, set:setSc, ph:"MAHLE, LINER..."},
                {label:"📅 DATE", val:sd, set:setSd, ph:"2024 or 11.2025"},
              ].map(f => (
                <div key={f.label}>
                  <div style={{fontSize:9, color:"#f5a623", marginBottom:4, letterSpacing:1}}>{f.label}</div>
                  <input value={f.val} onChange={e=>f.set(e.target.value)}
                    placeholder={f.ph} style={inp}/>
                </div>
              ))}
            </div>
            {(sf||sc||sd||sl) ? (
              <>
                <div style={{display:"flex", alignItems:"center", gap:10, marginBottom:10}}>
                  <span style={{fontSize:12, color:"#f5a623"}}>{searchRes.length} records mile</span>
                  <button onClick={()=>{setSf("");setSc("");setSd("");setSl("");}}
                    style={{background:"transparent", border:"1px solid #333", color:"#888",
                      borderRadius:6, padding:"4px 10px", fontSize:10, cursor:"pointer"}}>
                    ✕ Clear
                  </button>
                </div>
                {searchRes.length > 0 && (
                  <div style={{border:"1px solid "+S.border, borderRadius:8, overflow:"hidden"}}>
                    <div style={{display:"grid", gridTemplateColumns:"75px 90px 110px 1fr 85px",
                      background:"#1e1600", padding:"7px 10px", fontSize:9,
                      color:"#f5a623", letterSpacing:1, borderBottom:"1px solid "+S.border}}>
                      <div>LOCO</div><div>PA DATE</div><div>LOCATION</div>
                      <div>FAULT</div><div>EPD TYPE</div>
                    </div>
                    <div style={{maxHeight:"60vh", overflowY:"auto"}}>
                      {searchRes.map((r,i) => (
                        <div key={i} onClick={()=>setSelRec(r)}
                          style={{display:"grid", gridTemplateColumns:"75px 90px 110px 1fr 85px",
                            padding:"8px 10px", borderBottom:"1px solid "+S.border,
                            background:i%2===0?S.surface:"#0f0f0f", cursor:"pointer"}}>
                          <div style={{fontSize:11, color:"#f5a623", fontWeight:"bold"}}>{r.loco_no}</div>
                          <div style={{fontSize:11, color:S.muted, overflow:"hidden",
                            textOverflow:"ellipsis", whiteSpace:"nowrap"}}>{r.pa_date||"—"}</div>
                          <div style={{fontSize:11, overflow:"hidden",
                            textOverflow:"ellipsis", whiteSpace:"nowrap"}}>{r.location||"—"}</div>
                          <div style={{fontSize:11, overflow:"hidden",
                            textOverflow:"ellipsis", whiteSpace:"nowrap"}}>{r.fault||r.epd_reason||"—"}</div>
                          <div><Badge t={r.epd_type}/></div>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
              </>
            ) : (
              <div style={{textAlign:"center", color:S.muted, marginTop:50, fontSize:13}}>
                Upar search karo
              </div>
            )}
          </div>
        )}
      </div>

      {/* DETAIL MODAL */}
      {selRec && (
        <div onClick={()=>setSelRec(null)} style={{
          position:"fixed", inset:0, background:"rgba(0,0,0,0.9)",
          display:"flex", alignItems:"center", justifyContent:"center",
          zIndex:100, padding:16,
        }}>
          <div onClick={e=>e.stopPropagation()} style={{
            background:"#141414", border:"1px solid #f5a623",
            borderRadius:10, maxWidth:640, width:"100%",
            maxHeight:"85vh", overflowY:"auto", padding:20,
          }}>
            <div style={{display:"flex", justifyContent:"space-between",
              alignItems:"center", marginBottom:14}}>
              <div style={{fontSize:14, color:"#f5a623", fontWeight:"bold"}}>
                🚂 Loco {selRec.loco_no||selRec._ln}
                {selRec._c && <span style={{marginLeft:8, fontSize:10, color:S.greenT}}>★ Custom</span>}
              </div>
              <button onClick={()=>setSelRec(null)} style={{
                background:"transparent", border:"1px solid #333", color:"#aaa",
                borderRadius:6, padding:"4px 10px", fontSize:12, cursor:"pointer",
              }}>✕ Close</button>
            </div>
            <div style={{fontSize:10, color:S.muted, marginBottom:10, letterSpacing:1}}>— POWER ASSEMBLY —</div>
            <Field label="PA Date" val={selRec.pa_date}/>
            <Field label="Location" val={selRec.location}/>
            <Field label="Fault / Reason" val={selRec.fault}/>
            <Field label="Investigation" val={selRec.investigation}/>
            <Field label="Component Incoming" val={selRec.comp_in}/>
            <Field label="Component Outgoing" val={selRec.comp_out}/>
            <div style={{fontSize:10, color:S.muted, margin:"12px 0 10px", letterSpacing:1}}>— EPD —</div>
            <Field label="EPD Date" val={selRec.epd_date}/>
            <Field label="EPD Reason" val={selRec.epd_reason}/>
            <Field label="EPD In (Old)" val={selRec.epd_in}/>
            <Field label="EPD Out (New)" val={selRec.epd_out}/>
            {selRec.epd_type && <div style={{marginBottom:8}}><Badge t={selRec.epd_type}/></div>}
            <Field label="Remarks" val={selRec.remarks}/>
          </div>
        </div>
      )}
    </div>
  );
}
